tool_use_result.originalFile:
// Package valley is the canonical domain model of a valley host: what the
// host serves, independent of any machine that serves it.
//
// This file is deliberately not Nix. The NixOS module in this repo is one
// installer that consumes the model (`cue vet` + `cue export` at build
// time); other installers and tools read the same file. Deployment concerns
// — data directory, unix user, SSH keys — are machine integration and live
// with the installer, never here.
package valley

// #Host is a complete valley host declaration: the set of projects the
// host serves, and the durability policy for the data behind them.
#Host: {
	// projects maps a project name to its declaration. Names must be
	// filesystem- and URL-safe because they become on-disk directory
	// names ("<name>.git") and clone paths.
	projects: [=~"^[a-zA-Z0-9][a-zA-Z0-9._-]*$"]: #Project

	// The host's offsite-backup policy. Optional: a declaration without
	// it is a host without offsite backup, and evaluates exactly as it
	// did before this field existed.
	backup?: #Backup
}

// #Project is the unit of declaration. A project *has* stores; git is the
// only store type today, and it is nested rather than top-level on
// purpose — the valley is not committed to being git-only.
#Project: {
	// The project's git store.
	git: {
		// Whether the host serves a git repository for this project.
		// Disabling never deletes anything: an existing repository is
		// left untouched on disk, merely unmanaged.
		enable: bool | *true
	}

	// Push-mirror URLs. Every push to the primary is replicated to each
	// URL via `git push --mirror`, which propagates deletions — the
	// correct semantic for a mirror. Replication is best-effort: a dead
	// mirror never rejects the primary push. Credentials are the host's
	// concern (the installer documents how); they are not declared here.
	mirrors: [...string] | *[]
}

// #Backup is the durability policy for the host's data: that an offsite
// backup exists, how often it runs, and how long snapshots are kept. It is
// deliberately host-level — one data directory, one repository — because
// that is the host's reality today; per-project backup is a possible
// growth path (a `backup` on #Project), not a present need. Only policy
// is declared here: the repository URL, credentials, and host-key pinning
// are machine integration and live with the installer, never here.
#Backup: {
	// Whether offsite backup runs for the host's data. Disabling never
	// deletes anything: an existing backup repository is left untouched,
	// merely no longer written to or pruned.
	enable: bool | *true

	// The backup target kind. restic over sftp (a Hetzner Storage Box,
	// dcr-d7952bc) is the only target today; an object-store target
	// would widen this to a disjunction ("restic-s3") — deliberately not
	// before an implementation exists.
	target: "restic-sftp"

	// How often a snapshot is taken. "nightly" is the only cadence
	// today; its exact wall-clock rendering is the installer's choice.
	cadence: "nightly"

	// How many snapshots to keep per tier when pruning (restic
	// --keep-daily/--keep-weekly/--keep-monthly semantics). Every tier
	// keeps at least one snapshot — a zero tier would silently thin
	// history, so it is rejected rather than rendered.
	retention: {
		daily:   int & >0 | *7
		weekly:  int & >0 | *4
		monthly: int & >0 | *6
	}
}

// The top level of this package is itself a host declaration: a config
// file evaluated together with this schema is validated against #Host —
// unknown fields and unsafe project names are rejected.
//
//   cue vet -c schema/valley.cue <config>.cue
//   cue export schema/valley.cue <config>.cue
projects: #Host.projects

// Mirrors #Host.backup. CUE cannot reference an optional field, so the
// constraint is restated against the same definition.
backup?: #Backup

// A file's top level cannot be closed (embedding #Host would open it
// instead — embedding lifts closedness), so reject stray top-level fields
// explicitly: anything but the #Host fields — a `project:` typo, a
// deployment concern like `user:` — conflicts with this sentinel and
// fails vet with an error naming the field.
[!="projects" & !="backup"]: "INVALID: unknown top-level field; only \"projects\" and \"backup\" are allowed"

{
  description = "the-valley: the CUE domain schema for a valley host, and the NixOS module that installs one";

  inputs.nixpkgs.url = "github:NixOS/nixpkgs/nixos-25.11";

  outputs =
    { self, nixpkgs }:
    let
      lib = nixpkgs.lib;
      # Checks use import-from-derivation (the module's cue export), so they
      # are only defined for the system that can actually build them here.
      systems = [ "x86_64-linux" ];
    in
    {
      nixosModules.valley-host = ./nix/valley-host.nix;
      nixosModules.default = self.nixosModules.valley-host;

      checks = lib.genAttrs systems (
        system:
        let
          pkgs = nixpkgs.legacyPackages.${system};

          # Eval-only instantiation of the module — catches option-surface
          # and cue-export regressions without building or booting anything.
          # Each check host shares the machine baseline and supplies its own
          # declaration (and, where the declaration asks for backup, the
          # secret paths).
          mkHost =
            module:
            lib.nixosSystem {
              inherit system;
              modules = [
                self.nixosModules.default
                {
                  fileSystems."/" = {
                    device = "/dev/disk/by-label/nixos";
                    fsType = "ext4";
                  };
                  boot.loader.grub.enable = false;
                  system.stateVersion = "25.11";
                  services.valley = {
                    enable = true;
                    authorizedKeys = [ "ssh-ed25519 AAAAC3NzaC1lZDI1NTE5AAAAIPlaceholderKeyForEvalOnlyCheck0 valley-check" ];
                  };
                }
                module
              ];
            };

          # The example declaration enables backup, so this host supplies
          # the four secret paths (eval-only placeholders).
          host = mkHost {
            services.valley = {
              config = ./examples/host.cue;
              backup = {
                repositoryFile = "/run/agenix/valley-restic-repo";
                passwordFile = "/run/agenix/valley-restic-password";
                sshKeyFile = "/run/agenix/valley-git-ssh-key";
                knownHostsFile = "/var/lib/valley-backup/known_hosts";
              };
            };
          };

          # A declaration without a backup block predates the field and must
          # keep evaluating exactly as before: zero restic machinery.
          noBackupHost = mkHost {
            services.valley.config = pkgs.writeText "no-backup-host.cue" ''
              package valley
              projects: "the-valley": {}
            '';
          };

          # The example declaration with the secret paths left unset: the
          # module must refuse with assertions naming the missing options.
          noSecretsHost = mkHost {
            services.valley.config = ./examples/host.cue;
          };

          failedAssertions = builtins.filter (a: !a.assertion) (
            host.config.assertions ++ noBackupHost.config.assertions
          );

          missingSecretAssertions = builtins.filter (a: !a.assertion) noSecretsHost.config.assertions;

          resticRenderedWithoutDeclaration =
            noBackupHost.config.systemd.services ? "restic-backups-valley"
            || noBackupHost.config.systemd.timers ? "restic-backups-valley";
        in
        {
          # The example host declaration must vet against the schema, and the
          # schema must reject what it claims to reject: unsafe project names,
          # unknown project fields, stray top-level fields (typos, deployment
          # concerns), and malformed backup policy (machine concerns, targets
          # without an implementation, non-positive retention). CUE closedness
          # is easy to regress silently — e.g. embedding #Host instead of
          # referencing it opens the schema — so the rejections are pinned
          # here.
          cue-vet =
            let
              invalidConfigs = {
                unsafe-project-name = ''
                  package valley
                  projects: ".hidden": {}
                '';
                unknown-project-field = ''
                  package valley
                  projects: ok: dataDir: "/srv/git"
                '';
                top-level-typo = ''
                  package valley
                  project: oops: {}
                '';
                deployment-concern-in-cue = ''
                  package valley
                  user: "git"
                  projects: ok: {}
                '';
                machine-concern-in-backup = ''
                  package valley
                  projects: ok: {}
                  backup: repositoryFile: "/run/agenix/valley-restic-repo"
                '';
                unimplemented-backup-target = ''
                  package valley
                  projects: ok: {}
                  backup: target: "restic-s3"
                '';
                negative-retention = ''
                  package valley
                  projects: ok: {}
                  backup: retention: daily: -1
                '';
              };
            in
            pkgs.runCommand "valley-cue-vet"
              {
                nativeBuildInputs = [ pkgs.cue ];
              }
              ''
                cue vet -c ${./schema/valley.cue} ${./examples/host.cue}
                cue export ${./schema/valley.cue} ${./examples/host.cue} > example.json
                grep -q 'gunk-dev/the-valley' example.json
                grep -q 'restic-sftp' example.json

                # A declaration without a backup block must stay valid —
                # consumers written before the field existed keep vetting.
                cue vet -c ${./schema/valley.cue} ${pkgs.writeText "no-backup.cue" ''
                  package valley
                  projects: "the-valley": {}
                ''}

                ${lib.concatStrings (
                  lib.mapAttrsToList (name: cfg: ''
                    if cue vet -c ${./schema/valley.cue} ${pkgs.writeText "${name}.cue" cfg}; then
                      echo "cue-vet: expected invalid config '${name}' to be rejected" >&2
                      exit 1
                    fi
                  '') invalidConfigs
                )}
                touch $out
              '';

          module-eval =
            if failedAssertions != [ ] then
              throw "valley module-eval: failed assertions: ${lib.concatMapStringsSep "; " (a: a.message) failedAssertions}"
            else if resticRenderedWithoutDeclaration then
              throw "valley module-eval: restic machinery rendered for a declaration without a backup block"
            else if
              !(lib.any (a: lib.hasInfix "services.valley.backup." a.message) missingSecretAssertions)
            then
              throw "valley module-eval: enabling backup without the secret-path options must fail an assertion naming them"
            else
              pkgs.runCommand "valley-module-eval"
                {
                  initScript = host.config.systemd.services.valley-init.script;
                  sshdConfig = host.config.services.openssh.extraConfig;
                  resticService = host.config.systemd.units."restic-backups-valley.service".text;
                  resticTimer = host.config.systemd.units."restic-backups-valley.timer".text;
                  passAsFile = [
                    "initScript"
                    "sshdConfig"
                    "resticService"
                    "resticTimer"
                  ];
                }
                ''
                  # The repo init list and mirror hook must be generated from
                  # the CUE export, and the git user's sshd Match block must
                  # be terminated so it cannot scope later config.
                  grep -q "the-valley" "$initScriptPath"
                  grep -q "valley-mirrors" "$initScriptPath"
                  grep -q "Match All" "$sshdConfigPath"

                  # The rendered restic units must back up the data directory
                  # to the consumer-supplied repository with the declared
                  # retention over a pinned host key, on the declared cadence.
                  grep -q "RESTIC_REPOSITORY_FILE=/run/agenix/valley-restic-repo" "$resticServicePath"
                  grep -q -- "--keep-daily 7 --keep-weekly 4 --keep-monthly 6" "$resticServicePath"
                  grep -q "UserKnownHostsFile=/var/lib/valley-backup/known_hosts" "$resticServicePath"
                  grep -q "BatchMode=yes" "$resticServicePath"
                  grep -q "OnCalendar=03:30" "$resticTimerPath"

                  # The backup paths render as a --files-from list: follow
                  # ExecStartPre to that list and pin the data directory.
                  preStart="$(sed -n 's/^ExecStartPre=//p' "$resticServicePath" | head -n1)"
                  staticPaths="$(grep -o '/nix/store/[^ ]*-staticPaths' "$preStart" | head -n1)"
                  grep -qx "/srv/git" "$staticPaths"
                  touch $out
                '';
        }
      );
    };
}

# The valley host installer: declarative bare-git hosting over SSH, driven
# by a CUE host declaration (../schema/valley.cue).
#
# Layering: the CUE file owns the domain model — which projects exist, their
# stores, their push mirrors, whether the host's data has offsite backup and
# with what cadence and retention. This module owns machine integration
# only: data directory, unix user, SSH keys, backup credentials. At build
# time the CUE config is vetted against the shipped schema and exported to
# JSON; an invalid config fails the system build with cue's error. Nix
# never redefines the schema.
#
# Repos are only ever created, never deleted or overwritten — removing a
# project (or disabling its git store) leaves the data on disk untouched.
#
# Identity is deliberately thin and host-level: one git user, git-shell,
# key-only, Tailscale ACLs in front. Per-project access is not honestly
# enforceable with this mechanism, so it is deliberately not an option
# (.the-valley/decisions/dcr-0f5d9b1-cue-config-host-module.md).
#
# Mirror credentials are the consumer's concern: the module assumes the git
# user's SSH identity and known_hosts are provisioned by the host (e.g.
# cosmo, via its secrets). Nothing here plumbs secrets: the backup options
# below take *paths* to consumer-provisioned secret files; the contents
# never pass through this module or the store.
{
  config,
  pkgs,
  lib,
  ...
}:

let
  cfg = config.services.valley;

  schema = ../schema/valley.cue;

  # Build-time vet + export of the host declaration. the vet checks the
  # declaration against the schema (whose top level applies #Host), so unknown
  # fields and unsafe project names fail the build, with cue's error.
  configJSON =
    pkgs.runCommand "valley-config.json"
      {
        nativeBuildInputs = [ pkgs.cue ];
      }
      ''
        cue vet -c ${schema} ${cfg.config}
        cue export ${schema} ${cfg.config} > $out
      '';

  host = lib.importJSON configJSON;

  # Projects whose git store is enabled get a bare repository.
  gitProjects = lib.filterAttrs (_: p: p.git.enable) host.projects;
  repoNames = lib.attrNames gitProjects;

  # The declared durability policy, if any. `backup` is optional in the
  # schema: a declaration without it (or with enable = false) renders zero
  # backup machinery, exactly as before the field existed.
  backupPolicy = host.backup or null;
  backupEnabled = backupPolicy != null && backupPolicy.enable;

  # The declared cadence names policy; its wall-clock rendering is this
  # installer's choice. A lookup rather than a literal, so a cadence this
  # module does not know fails eval loudly instead of mis-scheduling.
  backupTimer = {
    # Late night with a spread; Persistent runs a missed window at boot.
    nightly = {
      OnCalendar = "03:30";
      RandomizedDelaySec = "30m";
      Persistent = true;
    };
  };

  # The secret-path options the consumer must supply once the declaration
  # enables backup, with what each names — for the assertion message.
  backupSecretOptions = {
    repositoryFile = "the restic repository URL";
    passwordFile = "the repository encryption password";
    sshKeyFile = "the SSH identity for the sftp target";
    knownHostsFile = "the pinned host key of the sftp target";
  };

  # Managed post-receive dispatcher. Each repo's post-receive is a symlink to
  # this script, which chains every executable dropped into the repo's
  # hooks/post-receive.d/ directory.
  postReceiveDispatch = pkgs.writeShellScript "valley-post-receive" ''
    # Managed by services.valley — do not edit.
    # Drop executable hooks into post-receive.d/ next to this symlink.
    set -eu
    hook_dir="$(dirname "$0")/post-receive.d"
    [ -d "$hook_dir" ] || exit 0
    updates="$(cat)"
    [ -n "$updates" ] || exit 0
    for hook in "$hook_dir"/*; do
      [ -x "$hook" ] || continue
      printf '%s\n' "$updates" | "$hook" "$@"
    done
  '';

  # Best-effort push replication. The pushes run detached (setsid) so a dead
  # mirror can only ever cost a log line — never block or fail the primary
  # push. Explicit refspecs with --prune force-update every branch and tag
  # and propagate their deletions — the same deletion semantics --mirror
  # gives for heads and tags. --mirror itself is rejected: it also tries to
  # delete remote-only namespaces, and on GitHub the read-only refs/pull/*
  # makes that fail every push, masking real replication failures.
  mirrorPusher =
    name: mirrors:
    pkgs.writeShellScript "valley-mirror-push-${name}" ''
      for url in ${lib.escapeShellArgs mirrors}; do
        if ${pkgs.git}/bin/git push --mirror "$url" >/dev/null 2>&1; then
          ${pkgs.util-linux}/bin/logger -t valley-mirror "${name}: pushed to $url" || true
        else
          ${pkgs.util-linux}/bin/logger -t valley-mirror "${name}: push to $url FAILED" || true
        fi
      done
    '';

  mirrorHook =
    name: mirrors:
    pkgs.writeShellScript "valley-mirrors-${name}" ''
      # Managed by services.valley — best-effort push mirrors for ${name}.
      cat >/dev/null   # updated refs unused: the push replicates all heads and tags
      ${pkgs.util-linux}/bin/setsid -f ${mirrorPusher name mirrors} </dev/null >/dev/null 2>&1
      exit 0
    '';

  # Per-project mirror-hook wiring. Only ever installs, updates, or removes
  # a store symlink — a hand-written hook of the same name is left alone.
  mirrorHookCommands = lib.concatStrings (
    lib.mapAttrsToList (
      name: p:
      let
        mhook = lib.escapeShellArg "${cfg.dataDir}/${name}.git/hooks/post-receive.d/valley-mirrors";
      in
      if p.mirrors != [ ] then
        ''
          mhook=${mhook}
          if [ -L "$mhook" ]; then
            case "$(readlink "$mhook")" in
              /nix/store/*) ln -sfn ${mirrorHook name p.mirrors} "$mhook" ;;
            esac
          elif [ ! -e "$mhook" ]; then
            ln -s ${mirrorHook name p.mirrors} "$mhook"
          fi
        ''
      else
        ''
          mhook=${mhook}
          if [ -L "$mhook" ]; then
            case "$(readlink "$mhook")" in
              /nix/store/*) rm -f "$mhook" ;;
            esac
          fi
        ''
    ) gitProjects
  );
in
{
  options.services.valley = {
    enable = lib.mkEnableOption "the valley host: declarative bare-git hosting driven by a CUE declaration";

    user = lib.mkOption {
      type = lib.types.str;
      default = "git";
      description = "System user that owns the repositories and accepts SSH pushes.";
    };

    group = lib.mkOption {
      type = lib.types.str;
      default = "git";
      description = "Primary group of the valley git user.";
    };

    dataDir = lib.mkOption {
      type = lib.types.path;
      default = "/srv/git";
      example = "/mnt/git";
      description = ''
        Directory holding the bare repositories, one `<name>.git` per
        project declared in {option}`services.valley.config`. Also the git
        user's home, so clone URLs are relative to it (`git@host:name.git`).
        Consumers typically point it at a dedicated dataset.
      '';
    };

    authorizedKeys = lib.mkOption {
      type = lib.types.listOf lib.types.str;
      default = [ ];
      description = ''
        SSH public keys allowed to push/fetch as the git user. Access is
        host-level by design: every key can reach every project.
      '';
    };

    config = lib.mkOption {
      type = lib.types.path;
      example = lib.literalExpression "./valley.cue";
      description = ''
        Path to the host's CUE declaration (`package valley`) — the
        canonical statement of what this valley host serves, validated
        against the shipped schema at build time. This is the single domain
        input: projects, their push mirrors, and the backup policy are
        declared here, never as Nix options.
      '';
    };

    # Machine integration for the declared backup policy. The declaration
    # states WHAT must hold (offsite backup, cadence, retention); these
    # options supply HOW on this machine — where the repository is and how
    # to authenticate. All are paths to files the consumer provisions
    # (e.g. agenix), required when the declaration enables backup. Point
    # them at runtime paths, never at files in the Nix store.
    backup = {
      repositoryFile = lib.mkOption {
        type = lib.types.nullOr lib.types.path;
        default = null;
        example = "/run/agenix/valley-restic-repo";
        description = ''
          File containing the restic repository URL, for the sftp target
          e.g. `sftp://u123456@u123456.your-storagebox.de:23//./backups/valley`.
        '';
      };

      passwordFile = lib.mkOption {
        type = lib.types.nullOr lib.types.path;
        default = null;
        example = "/run/agenix/valley-restic-password";
        description = ''
          File containing the restic repository encryption password.
          Losing it loses the backups — keep a copy somewhere that
          survives this host.
        '';
      };

      sshKeyFile = lib.mkOption {
        type = lib.types.nullOr lib.types.path;
        default = null;
        example = "/run/agenix/valley-git-ssh-key";
        description = ''
          SSH private key that authenticates to the sftp target. The
          backup service runs as root, so any identity the target
          authorizes works — reusing the mirror key is fine.
        '';
      };

      knownHostsFile = lib.mkOption {
        type = lib.types.nullOr lib.types.path;
        default = null;
        example = "/var/lib/valley-backup/known_hosts";
        description = ''
          known_hosts file pinning the sftp target's host key. Pin from
          the provider's published fingerprints, not a blind ssh-keyscan.
        '';
      };
    };
  };

  config = lib.mkIf cfg.enable {
    assertions = [
      {
        assertion = cfg.authorizedKeys != [ ];
        message = "services.valley.authorizedKeys must not be empty — the git user would be unreachable.";
      }
    ]
    ++ lib.optionals backupEnabled (
      lib.mapAttrsToList (name: what: {
        assertion = cfg.backup.${name} != null;
        message = "services.valley.backup.${name} must be set: the host declaration enables backup, and ${what} is machine integration the consumer supplies (e.g. from its secrets).";
      }) backupSecretOptions
    );

    users.groups.${cfg.group} = { };

    users.users.${cfg.user} = {
      isSystemUser = true;
      group = cfg.group;
      home = cfg.dataDir;
      # git-shell only allows git-upload-pack/git-receive-pack/git-upload-archive;
      # interactive logins are rejected (no ~/git-shell-commands).
      shell = "${pkgs.git}/bin/git-shell";
      openssh.authorizedKeys.keys = cfg.authorizedKeys;
    };

    services.openssh.enable = lib.mkDefault true;

    # Belt-and-braces hardening for the git user. The trailing `Match All`
    # closes the block so it can't scope directives appended to sshd_config
    # after this snippet.
    services.openssh.extraConfig = ''
      Match User ${cfg.user}
        AllowTcpForwarding no
        AllowAgentForwarding no
        X11Forwarding no
        PermitTunnel no
      Match All
    '';

    # git-shell spawns git-receive-pack/git-upload-pack from PATH
    environment.systemPackages = [ pkgs.git ];

    systemd.tmpfiles.rules = [
      "d ${cfg.dataDir} 0750 ${cfg.user} ${cfg.group} - -"
    ];

    # Create missing bare repos and (re)wire the managed hooks on every
    # activation where the declaration changed.
    systemd.services.valley-init = {
      description = "Initialize the valley host's bare git repositories";
      wantedBy = [ "multi-user.target" ];
      after = [ "systemd-tmpfiles-setup.service" ];
      unitConfig.RequiresMountsFor = cfg.dataDir;
      serviceConfig = {
        Type = "oneshot";
        User = cfg.user;
        Group = cfg.group;
      };
      path = [ pkgs.git ];
      script = ''
        repos=( ${lib.escapeShellArgs repoNames} )
        for name in "''${repos[@]}"; do
          repo="${cfg.dataDir}/$name.git"
          # Check HEAD rather than the directory itself so a pre-existing
          # empty directory still gets initialized.
          if [ ! -e "$repo/HEAD" ]; then
            git init --bare --initial-branch=main "$repo"
          fi

          # Hook scaffolding: post-receive dispatches to post-receive.d/.
          # Only manage the hook if it is absent or already ours (a store
          # symlink) — a hand-written hook is left alone.
          mkdir -p "$repo/hooks/post-receive.d"
          hook="$repo/hooks/post-receive"
          if [ -L "$hook" ]; then
            case "$(readlink "$hook")" in
              /nix/store/*) ln -sfn ${postReceiveDispatch} "$hook" ;;
            esac
          elif [ ! -e "$hook" ]; then
            ln -s ${postReceiveDispatch} "$hook"
          fi
        done

        # Per-project push-mirror hooks.
        ${mirrorHookCommands}
      '';
    };

    # Offsite backup, rendered only when the declaration asks for it. The
    # declaration states the policy — that backup exists, its cadence and
    # retention; the services.valley.backup.* options supply the machine
    # half. Declaration absent or disabled ⇒ no restic config at all.
    services.restic.backups = lib.mkIf backupEnabled {
      valley = {
        initialize = true;
        repositoryFile = cfg.backup.repositoryFile;
        passwordFile = cfg.backup.passwordFile;
        paths = [ cfg.dataDir ];
        # The schema admits only the restic-sftp target today; a second
        # target would grow a dispatch here. The service runs as root:
        # authenticate with the supplied identity and only the pinned
        # host key. No prompt can be answered inside a systemd unit, so
        # BatchMode + strict host key checking turn a would-be hang into
        # an immediate error.
        extraOptions = [
          "sftp.args='-i ${cfg.backup.sshKeyFile} -o UserKnownHostsFile=${cfg.backup.knownHostsFile} -o IdentitiesOnly=yes -o BatchMode=yes -o StrictHostKeyChecking=yes'"
        ];
        timerConfig = backupTimer.${backupPolicy.cadence};
        pruneOpts = [
          "--keep-daily ${toString backupPolicy.retention.daily}"
          "--keep-weekly ${toString backupPolicy.retention.weekly}"
          "--keep-monthly ${toString backupPolicy.retention.monthly}"
        ];
      };
    };
  };
}
